import React, { useState } from "react";
import { useNavigate } from "react-router-dom";
import "./ConsultancyPage.css";

function ConsultancyPage() {
  const navigate = useNavigate();
  const [searchQuery, setSearchQuery] = useState("");
  const [activeDropdown, setActiveDropdown] = useState(null);

  const doctorsData = {
    "General Physician": [
      {
        name: "Dr. Rachna Kucherira",
        img: "https://cdn.pixabay.com/photo/2016/03/31/20/11/doctor-1295568_960_720.png",
        details:
          "MD (Community Medicine), AIIMS New Delhi — 30+ years of experience",
        languages: "Speaks Hindi, English",
        fee: "₹1000",
      },
      {
        name: "Dr. Rashmi Gupta Bajpai",
        img: "https://cdn.pixabay.com/photo/2014/04/03/10/32/doctor-310845_960_720.png",
        details:
          "MBBS Govt Medical College, Trivandrum — 24+ years of experience",
        languages: "Speaks Hindi, English, Malayalam, Punjabi",
        fee: "₹700",
      },
    ],
    Pediatrics: [
      {
        name: "Dr. Aarav Mehta",
        img: "https://cdn.pixabay.com/photo/2016/03/31/20/11/doctor-1295568_960_720.png",
        details:
          "MD (Pediatrics), AIIMS Delhi — 15+ years of experience in child care",
        languages: "Speaks Hindi, English",
        fee: "₹850",
      },
    ],
  };

  const filteredDoctors = Object.keys(doctorsData).reduce((acc, key) => {
    const filtered = doctorsData[key].filter((doc) =>
      doc.name.toLowerCase().includes(searchQuery.toLowerCase())
    );
    if (filtered.length) acc[key] = filtered;
    return acc;
  }, {});

  return (
    <div className="consultancy-page">
      {/* === Back Button === */}
      <button className="back-btn" onClick={() => navigate(-1)}>
        ← Back
      </button>

      {/* === Header Section === */}
      <div className="consultancy-header">
        <h1>Our Doctors</h1>
        <p>
          We have handpicked some of the best doctors in key specialties. Whether
          you’re looking for a General Physician or a Pediatrician — you’ll find
          trusted professionals here.
        </p>

        <div className="search-bar">
          <input
            type="text"
            placeholder="Search doctor or specialty..."
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
          />
          <button>Search</button>
        </div>
      </div>

      {/* === Doctor Categories === */}
      <div className="doctor-sections">
        {Object.keys(filteredDoctors).map((category, index) => (
          <div key={index} className="doctor-category">
            <div
              className="category-header"
              onClick={() =>
                setActiveDropdown(activeDropdown === category ? null : category)
              }
            >
              <h2>{category}</h2>
              <span className={`arrow ${activeDropdown === category ? "open" : ""}`}>
                ▼
              </span>
            </div>

            {activeDropdown === category && (
              <div className="doctor-list">
                {filteredDoctors[category].map((doc, i) => (
                  <div className="doctor-card" key={i}>
                    <img src={doc.img} alt={doc.name} />
                    <div className="doctor-info">
                      <h3>{doc.name}</h3>
                      <p>{doc.details}</p>
                      <p className="languages">{doc.languages}</p>
                      <div className="consultation">
                        <span>{doc.fee} per consultation</span>
                        <div className="buttons">
                          <button className="view-btn">View Profile</button>
                          <button className="book-btn">Book Appointment</button>
                        </div>
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        ))}

        {Object.keys(filteredDoctors).length === 0 && (
          <p className="no-results">No doctors found for "{searchQuery}"</p>
        )}
      </div>
    </div>
  );
}

export default ConsultancyPage;
